using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class LabelMapping
{
    public required string[] Labels { get; init; }
}

using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public static class ModelTrainer
{
    public static string[] TrainAndEvaluate(string dataPath, string modelPath, ILogger logger)
    {
        var mlContext = new MLContext(seed: 42);

        var data = mlContext.Data.LoadFromTextFile<TicketInput>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = mlContext.Transforms.Text
            .FeaturizeText("SubjectFeaturized", nameof(TicketInput.Subject))
            .Append(mlContext.Transforms.Text
                .FeaturizeText("DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketInput.Category)))
            .Append(mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        // Evaluate on held-out test set
        var splitModel = pipeline.Fit(split.TrainSet);
        var testPredictions = splitModel.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(testPredictions);

        logger.LogInformation("===== Model Evaluation Metrics =====");
        logger.LogInformation("Macro Accuracy:    {MacroAccuracy:F4}", metrics.MacroAccuracy);
        logger.LogInformation("Micro Accuracy:    {MicroAccuracy:F4}", metrics.MicroAccuracy);
        logger.LogInformation("Log Loss:          {LogLoss:F4}", metrics.LogLoss);
        logger.LogInformation("Log Loss Reduction: {LogLossReduction:F4}", metrics.LogLossReduction);
        logger.LogInformation("Confusion Matrix:\n{ConfusionMatrix}",
            metrics.ConfusionMatrix.GetFormattedConfusionTable());

        // Retrain on the full dataset for the production model
        var model = pipeline.Fit(data);
        mlContext.Model.Save(model, data.Schema, modelPath);
        logger.LogInformation("Model saved to {ModelPath}", modelPath);

        // Extract label ordering from the Score column slot names
        var transformedData = model.Transform(data);
        var scoreColumn = transformedData.Schema["Score"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        scoreColumn.GetSlotNames(ref slotNames);
        var labels = slotNames.DenseValues().Select(v => v.ToString()).ToArray();

        logger.LogInformation("Label order: {Labels}", string.Join(", ", labels));
        return labels;
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/tickets")]
public class TicketClassifierController(
    PredictionEnginePool<TicketInput, TicketPrediction> predictionEnginePool,
    LabelMapping labelMapping) : ControllerBase
{
    [HttpPost("classify")]
    public IActionResult Classify([FromBody] ClassifyRequest request)
    {
        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = predictionEnginePool.Predict(input);

        var scores = labelMapping.Labels
            .Zip(prediction.Score)
            .ToDictionary(pair => pair.First, pair => Math.Round(pair.Second, 4));

        return Ok(new ClassifyResponse(
            prediction.Category,
            Math.Round(prediction.Score.Max(), 4),
            scores));
    }
}

public record ClassifyRequest(string Subject, string Description, float Priority);
public record ClassifyResponse(string Category, double Confidence, Dictionary<string, double> Scores);

