using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/tickets")]
public class TicketClassifierController(
    PredictionEnginePool<TicketInput, TicketPrediction> predictionEnginePool,
    LabelMapping labelMapping) : ControllerBase
{
    [HttpPost("classify")]
    public IActionResult Classify([FromBody] ClassifyRequest request)
    {
        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = predictionEnginePool.Predict(input);

        var scores = labelMapping.Labels
            .Zip(prediction.Score)
            .ToDictionary(pair => pair.First, pair => Math.Round(pair.Second, 4));

        return Ok(new ClassifyResponse(
            prediction.Category,
            Math.Round(prediction.Score.Max(), 4),
            scores));
    }
}

public record ClassifyRequest(string Subject, string Description, float Priority);
public record ClassifyResponse(string Category, double Confidence, Dictionary<string, double> Scores);

